&lt;style&gt;
        .form-group {
            margin-bottom: 1rem;
        }

        .form-group label {
            display: block;
            margin-bottom: 0.5rem;
        }

        .form-group input[type=&quot;text&quot;],
        .form-group input[type=&quot;file&quot;],
        .form-group select,
        .form-group textarea {
            width: 100%;
            padding: 0.5rem;
            border: 1px solid #ddd;
            border-radius: 4px;
        }

        .form-group textarea {
            resize: vertical;
        }

        .form-actions {
            margin-top: 1.5rem;
        }

        .form-actions button {
            margin-right: 10px;
        }

        .error-message {
            color: #dc3545;
            font-size: 0.875rem;
            margin-top: 0.25rem;
        }

        .current-image {
            margin: 1rem 0;
        }

        .current-image img {
            max-width: 200px;
            height: auto;
        }

        .ck-editor__editable {
            min-height: 300px;
        }

        /* 媒体库样式 */
        .media-item {
            cursor: pointer;
            transition: all 0.2s ease;
            position: relative;
        }

        .media-item:hover {
            transform: translateY(-2px);
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
        }

        .media-item.selected {
            border: 2px solid #007bff;
            box-shadow: 0 0 0 3px rgba(0, 123, 255, 0.25);
        }

        .media-item .card-img-wrapper {
            position: relative;
        }

        .media-item .select-overlay {
            z-index: 10;
        }

        .media-item .select-overlay input[type=&quot;checkbox&quot;] {
            width: 18px;
            height: 18px;
            cursor: pointer;
        }
    &lt;/style&gt;
